// Test to reproduce the bug
async function testBug() {
  console.log('Testing presetWind4 with important option...')

  // Create UnoCSS generator with presetWind4 and important option set to '#__nuxt'
  const uno = createGenerator({
    presets: [
      presetWind4({
        important: '#__nuxt'
      })
    ]
  })

  // Generate CSS for text-red utility
  const { css } = await uno.generate('text-red')

  console.log('Generated CSS:')
  console.log(css)

  // Check if CSS contains undefined --un-text-opacity variable
  if (css.includes('var(--un-text-opacity)') && !css.includes('--un-text-opacity:')) {
    console.log('❌ BUG REPRODUCED: --un-text-opacity is referenced but not defined')
    return true
  } else {
    console.log('✅ Bug not reproduced')
    return false
  }
}

// Run the test
testBug().then(bugReproduced => {
  if (bugReproduced) {
    console.log('\nBug successfully reproduced!')
  } else {
    console.log('\nBug not reproduced in this test')
  }
}).catch(error => {
  console.error('Error running test:', error)
})

