// Check if the --un-text-opacity variable is properly tracked
const fs = require('fs');
const path = require('path');

// Read the color resolver file to understand how text opacity is handled
const colorResolverPath = path.join(__dirname, 'packages-presets/preset-wind4/src/utils/utilities.ts');
const colorResolverContent = fs.readFileSync(colorResolverPath, 'utf8');

// Look for the colorCSSGenerator function
const colorCSSGeneratorMatch = colorResolverContent.match(/export function colorCSSGenerator[\s\S]*?\n}/);
if (colorCSSGeneratorMatch) {
  console.log('Found colorCSSGenerator function');

  // Check if it defines the --un-text-opacity property
  if (colorCSSGeneratorMatch[0].includes('--un-text-opacity')) {
    console.log('colorCSSGenerator defines --un-text-opacity');
  }

  // Check if it uses defineProperty
  if (colorCSSGeneratorMatch[0].includes('defineProperty')) {
    console.log('colorCSSGenerator uses defineProperty');
  }
}

