const propertiesContent = fs.readFileSync(propertiesPath, 'utf8');

console.log('\nPreflight properties code:');
console.log(propertiesContent);

// The issue is likely that when using important: '#__nuxt', the postprocessor
// wraps selectors but the property definitions (like --un-text-opacity) are not
// properly included in the final CSS output

