import { createGenerator } from '@unocss/core'
import presetWind4 from '@unocss/preset-wind4'

async function testImportantBug() {
  console.log('Testing presetWind4 with important: "#__nuxt" option...\n')

  // Test 1: Without important option (should work correctly)
  const unoNormal = createGenerator({
    envMode: 'dev',
    presets: [
      presetWind4({
        preflights: { reset: false },
      }),
    ],
  })

  const { css: normalCss } = await unoNormal.generate('text-red')
  console.log('1. Normal usage (without important option):')
  console.log(normalCss)
  console.log('')

  // Test 2: With important: '#__nuxt' (this should reproduce the bug)
  const unoImportant = createGenerator({
    envMode: 'dev',
    presets: [
      presetWind4({
        important: '#__nuxt',
        preflights: { reset: false },
      }),
    ],
  })

  const { css: importantCss } = await unoImportant.generate('text-red')
  console.log('2. With important: "#__nuxt" (bug reproduction):')
  console.log(importantCss)
  console.log('')

  // Check if the bug is reproduced
  const hasOpacityVar = importantCss.includes('var(--un-text-opacity)')
  const hasOpacityDefinition = importantCss.includes('--un-text-opacity:')

  console.log('Analysis:')
  console.log(`- CSS contains var(--un-text-opacity): ${hasOpacityVar}`)
  console.log(`- CSS contains --un-text-opacity definition: ${hasOpacityDefinition}`)

  if (hasOpacityVar && !hasOpacityDefinition) {
    console.log('\n❌ BUG REPRODUCED: --un-text-opacity is referenced but not defined!')
    return true
  } else {
    console.log('\n✅ Bug not reproduced in this test')
    return false
  }
}

testImportantBug().catch(console.error)

