import { createGenerator } from '@unocss/core'
import presetWind4 from '@unocss/preset-wind4'

async function debugImportantBug() {
  console.log('Debugging presetWind4 with important: "#__nuxt"...\n')

  // Test with important selector
  const uno = await createGenerator({
    presets: [
      presetWind4({
        important: '#__nuxt',
        preflights: {
          reset: false,
          theme: 'on-demand'
        },
      }),
    ],
  })

  console.log('=== Generating CSS for text-red ===')
  const { css, layers } = await uno.generate('text-red')

  console.log('Full CSS:')
  console.log(css)
  console.log('\n')

  console.log('Layers:')
  console.log(Object.keys(layers))
  console.log('\n')

  // Check each layer
  for (const [layerName, layerContent] of Object.entries(layers)) {
    console.log(`Layer "${layerName}":`)
    console.log(layerContent)
    console.log('---')
  }

  // Analyze the issue
  console.log('\n=== Analysis ===')

  // Check if properties layer is present but contains invalid CSS
  const hasPropertiesLayer = layers.properties && layers.properties.trim()
  console.log(`Properties layer exists: ${!!hasPropertiesLayer}`)

  if (hasPropertiesLayer) {
    console.log('Properties layer content:')
    console.log(layers.properties)

    // Check if @property rule is malformed
    const hasAtProperty = layers.properties.includes('@property')
    const hasBadSelector = layers.properties.includes('#__nuxt') && layers.properties.includes('@property')

    console.log(`\n- Contains @property rule: ${hasAtProperty}`)
    console.log(`- @property rule has wrong selector: ${hasBadSelector}`)

    if (hasBadSelector) {
      console.log('\n❌ BUG FOUND: @property rule is being wrapped with #__nuxt selector!')
    }
  }
}

debugImportantBug().catch(console.error)

